import { useEffect, useState } from "react";

function App() {
  const [questions, setQuestions] = useState([]);
  const [selected, setSelected] = useState({});

  useEffect(() => {
    fetch("http://localhost:3000/api/quiz")
      .then(res => res.json())
      .then(data => setQuestions(data));
  }, []);

  const handleSelect = (qid, opt) => {
    setSelected(prev => ({ ...prev, [qid]: opt }));
  };

  return (
    <div style={{
      minHeight: "100vh",
      background: "radial-gradient(circle at top, #1f1c2c, #928dab)",
      fontFamily: "Inter, sans-serif",
      padding: "40px",
      color: "white"
    }}>

      {/* HEADER */}
      <div style={{ textAlign: "center", marginBottom: "50px" }}>
        <h1 style={{
          fontSize: "42px",
          fontWeight: "700",
          letterSpacing: "1px"
        }}>
          Online Exam - v1
        </h1>
        <p style={{ opacity: 0.7 }}>Harshith B - 23MIS0012</p>
      </div>

      {/* QUESTIONS */}
      <div style={{
        maxWidth: "750px",
        margin: "auto",
        display: "flex",
        flexDirection: "column",
        gap: "25px"
      }}>

        {questions.map(q => (
          <div key={q.id} style={{
            background: "rgba(255,255,255,0.08)",
            padding: "25px",
            borderRadius: "16px",
            backdropFilter: "blur(12px)",
            boxShadow: "0 10px 30px rgba(0,0,0,0.3)",
            transition: "0.3s"
          }}>

            <p style={{
              fontSize: "18px",
              marginBottom: "15px",
              fontWeight: "500"
            }}>
              {q.question}
            </p>

            {q.options.map(opt => {
              const isSelected = selected[q.id] === opt;

              return (
                <div
                  key={opt}
                  onClick={() => handleSelect(q.id, opt)}
                  style={{
                    padding: "12px 16px",
                    marginBottom: "10px",
                    borderRadius: "10px",
                    cursor: "pointer",
                    border: isSelected
                      ? "2px solid #00f5ff"
                      : "1px solid rgba(255,255,255,0.2)",
                    background: isSelected
                      ? "rgba(0,245,255,0.15)"
                      : "rgba(255,255,255,0.05)",
                    transition: "all 0.2s ease",
                  }}
                >
                  {opt}
                </div>
              );
            })}
          </div>
        ))}

      </div>
    </div>
  );
}

export default App;
